14	type NeighborEntry = { cell: Cell; count: number };
15	
16	const countNeighbors = (cells: readonly Cell[]): Map<string, NeighborEntry> => {
17	  const counts = new Map<string, NeighborEntry>();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const cell: Cell = [x + dx, y + dy];
21	      const key = toKey(cell);
22	      const entry = counts.get(key);
23	      if (entry) entry.count++;
24	      else counts.set(key, { cell, count: 1 });
25	    }
26	  }
27	  return counts;
28	};
