30	export function nextGeneration(cells: readonly Cell[]): readonly Cell[] {
31	  const aliveKeys = new Set(cells.map(toKey));
32	  const result: Cell[] = [];
33	  for (const [key, { cell, count }] of countNeighbors(cells)) {
34	    if (livesNextGeneration(aliveKeys.has(key), count)) result.push(cell);
35	  }
36	  return result;
