type CandidateCell = { cell: Cell; isAlive: boolean; neighborCount: number };

const collectCandidates = (cells: readonly Cell[]): Iterable<CandidateCell> => {
  const candidates = new Map<string, CandidateCell>();
  const candidateAt = (cell: Cell): CandidateCell => {
    const key = toKey(cell);
    const existing = candidates.get(key);
    if (existing) return existing;
    const created: CandidateCell = { cell, isAlive: false, neighborCount: 0 };
    candidates.set(key, created);
    return created;
  };
  for (const cell of cells) {
    candidateAt(cell).isAlive = true;
    const [x, y] = cell;
    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
      candidateAt([x + dx, y + dy]).neighborCount++;
    }
  }
  return candidates.values();
};

export function nextGeneration(cells: readonly Cell[]): readonly Cell[] {
  const result: Cell[] = [];
  for (const { cell, isAlive, neighborCount } of collectCandidates(cells)) {
    if (livesNextGeneration(isAlive, neighborCount)) result.push(cell);
  }
  return result;
}

